                          <div 
                            key={serviceTypeIndex} 
                            className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-shadow"
                          >
                            {/* Service Type Header */}
                            <div className="flex items-center justify-between p-6 border-b border-gray-100">
                              <div className="flex items-center space-x-4 flex-1">
                                <div className="p-2 bg-teal-100 rounded-lg">
                                  <FiTag className="w-5 h-5 text-teal-600" />
                                </div>
                                <div className="flex-1">
                                  <input
                                    type="text"
                                    value={serviceType.service_type_name}
                                    onChange={(e) => updateServiceTypeName(serviceTypeIndex, e.target.value)}
                                    placeholder="Enter service type name (e.g., 1 BHK, 2 BHK)"
                                    className="text-xl font-semibold text-gray-900 bg-transparent border-none outline-none w-full placeholder-gray-400 focus:ring-2 focus:ring-teal-500 rounded px-2 py-1"
                                  />
                                  <div className="text-sm text-gray-500 mt-1">
                                    {serviceType.pricing_fields?.length || 0} pricing fields
                                  </div>
                                </div>
                              </div>
                              <div className="flex items-center space-x-2">
                                {editingServiceTypes.length > 1 && (
                                  <button
                                    onClick={() => removeServiceType(serviceTypeIndex)}
                                    className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors"
                                    title="Remove Service Type"
                                  >
                                    <FiTrash2 className="w-4 h-4" />
                                  </button>
                                )}
                                <button
                                  onClick={() => addPricingField(serviceTypeIndex)}
                                  className="p-2 text-teal-600 hover:text-teal-700 hover:bg-teal-50 rounded-lg transition-colors"
                                  title="Add Pricing Field"
                                >
                                  <FiPlus className="w-4 h-4" />
                                </button>
                              </div>
                            </div>

                            {/* Pricing Fields */}
                            <div className="p-6">
                              <div className="mb-4">
                                <h4 className="text-lg font-semibold text-gray-800 mb-3 flex items-center">
                                  <FiDollarSign className="w-5 h-5 mr-2 text-green-600" />
                                  Pricing Structure
                                </h4>
                              </div>

                              <div className="space-y-3">
                                {serviceType.pricing_fields?.map((field: any, fieldIndex: number) => (
                                  <div 
                                    key={fieldIndex} 
                                    className="flex items-center space-x-4 p-4 bg-gray-50 rounded-lg border border-gray-200 hover:border-teal-300 transition-colors"
                                  >
                                    <div className="flex-1">
                                      <label className="block text-sm font-medium text-gray-700 mb-1">
                                        Room Size
                                      </label>
                                      <input
                                        type="text"
                                        value={field.room_size}
                                        onChange={(e) => updatePricingField(serviceTypeIndex, fieldIndex, 'room_size', e.target.value)}
                                        placeholder="e.g., 1 BHK, 2 BHK, 1000 sq ft"
                                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                                      />
                                    </div>
                                    <div className="flex-1">
                                      <label className="block text-sm font-medium text-gray-700 mb-1">
                                        Price (₹)
                                      </label>
                                      <div className="relative">
                                        <span className="absolute left-3 top-2 text-gray-500">₹</span>
                                        <input
                                          type="number"
                                          value={field.price}
                                          onChange={(e) => updatePricingField(serviceTypeIndex, fieldIndex, 'price', e.target.value)}
                                          placeholder="0.00"
                                          className="w-full pl-8 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                                        />
                                      </div>
                                    </div>
                                    {serviceType.pricing_fields.length > 1 && (
                                      <button
                                        onClick={() => removePricingField(serviceTypeIndex, fieldIndex)}
                                        className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors mt-6"
                                        title="Remove Pricing Field"
                                      >
                                        <FiTrash2 className="w-4 h-4" />
                                      </button>
                                    )}
                                  </div>
                                ))}
                              </div>

                              {/* Add Pricing Field Button */}
                              <button
                                onClick={() => addPricingField(serviceTypeIndex)}
                                className="mt-4 w-full py-3 border-2 border-dashed border-teal-300 text-teal-600 hover:text-teal-700 hover:border-teal-400 rounded-lg transition-colors flex items-center justify-center"
                              >
                                <FiPlus className="w-4 h-4 mr-2" />
                                Add Pricing Field
                              </button>
                            </div>
                          </div>
                        ))}
                      </div>

                      {/* Empty State */}
                      {editingServiceTypes.length === 0 && (
                        <div className="text-center py-12">
                          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <FiPackage className="w-8 h-8 text-gray-400" />
                          </div>
                          <h3 className="text-lg font-semibold text-gray-900 mb-2">No Service Types</h3>
                          <p className="text-gray-600 mb-4">Get started by adding your first service type and pricing structure.</p>
                          <button
                            onClick={addServiceType}
                            className="px-6 py-3 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors"
                          >
                            Add First Service Type
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>

              {/* Sidebar - Actions & Summary */}
              <div className="w-80 bg-gray-50 border-l border-gray-200 p-6">
                <div className="sticky top-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                    <FiSettings className="w-5 h-5 mr-2 text-gray-600" />
                    Actions & Summary
                  </h3>

                  {/* Summary Stats */}
                  <div className="bg-white rounded-lg p-4 mb-6 border border-gray-200">
                    <h4 className="font-semibold text-gray-900 mb-3">Summary</h4>
                    <div className="space-y-3">
                      <div className="flex justify-between">
                        <span className="text-gray-600">Service Types:</span>
                        <span className="font-semibold">{editingServiceTypes.length}</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-gray-600">Total Fields:</span>
                        <span className="font-semibold">
                          {editingServiceTypes.reduce((total, type) => total + (type.pricing_fields?.length || 0), 0)}
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-gray-600">Avg Price:</span>
                        <span className="font-semibold">
                          ₹{(() => {
                            const allPrices = editingServiceTypes.flatMap(type => 
                              type.pricing_fields?.map((field: any) => Number(field.price)) || []
                            ).filter(price => !isNaN(price));
                            return allPrices.length > 0 
                              ? (allPrices.reduce((sum, price) => sum + price, 0) / allPrices.length).toFixed(0)
                              : '0';
                          })()}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Quick Actions */}
                  <div className="bg-white rounded-lg p-4 mb-6 border border-gray-200">
                    <h4 className="font-semibold text-gray-900 mb-3">Quick Actions</h4>
                    <div className="space-y-2">
                      <button
                        onClick={addServiceType}
                        className="w-full text-left p-2 text-teal-600 hover:bg-teal-50 rounded transition-colors flex items-center"
                      >
                        <FiPlus className="w-4 h-4 mr-2" />
                        Add Service Type
                      </button>
                      <button
                        onClick={() => {
                          // Duplicate first service type
                          if (editingServiceTypes.length > 0) {
                            const duplicated = JSON.parse(JSON.stringify(editingServiceTypes[0]));
                            duplicated.service_type_name = `${duplicated.service_type_name} (Copy)`;
                            setEditingServiceTypes([...editingServiceTypes, duplicated]);
                          }
                        }}
                        className="w-full text-left p-2 text-blue-600 hover:bg-blue-50 rounded transition-colors flex items-center"
                      >
                        <FiCopy className="w-4 h-4 mr-2" />
                        Duplicate Type
                      </button>
                    </div>
                  </div>

                  {/* Save Actions */}
                  <div className="space-y-3">
                    <button
                      onClick={submitServiceChanges}
                      disabled={isSubmitting}
                      className="w-full py-3 bg-teal-600 text-white rounded-lg hover:bg-teal-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center justify-center font-semibold"
                    >
                      {isSubmitting ? (
                        <>
                          <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                          Saving Changes...
                        </>
                      ) : (
                        <>
                          <FiSave className="w-4 h-4 mr-2" />
                          Save Changes
                        </>
                      )}
                    </button>
                    <button
                      onClick={() => setServiceDetailsModalOpen(false)}
                      className="w-full py-2 text-gray-600 hover:text-gray-800 transition-colors"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Offer Details Modal */}
      {offerDetailsModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-2xl w-full mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-6 border-b">
              <h2 className="text-xl font-bold text-gray-900">
                Offer Details: {selectedOffer?.offer_name}
              </h2>
              <button
                onClick={() => setOfferDetailsModalOpen(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <FiX className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6">
              <div className="space-y-6">
                {/* Offer Information */}
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Offer Information</h3>
                  <div className="bg-gray-50 rounded-lg p-4 space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Offer Name:</span>
                        <p className="text-gray-900 font-medium">{selectedOffer?.offer_name}</p>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">Coupon Code:</span>
                        <p className="text-gray-900 font-mono bg-white px-2 py-1 rounded border">{selectedOffer?.coupon_number}</p>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Discount:</span>
                        <p className="text-green-600 font-bold text-lg">{selectedOffer?.offer_percentage}% off</p>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">Status:</span>
                        <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                          selectedOffer?.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                        }`}>
                          {selectedOffer?.status}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Start Date:</span>
                        <p className="text-gray-900">{formatDate(selectedOffer?.offer_starts_on)}</p>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">End Date:</span>
                        <p className="text-gray-900">{formatDate(selectedOffer?.expires_on)}</p>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Offer Banner */}
                {selectedOffer?.offer_banner_location && (
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-4">Offer Banner</h3>
                    <div className="bg-gray-50 rounded-lg p-4">
                      <img 
                        src={`${API_BASE_URL}offer-banner/${selectedOffer.offer_banner_location}`}
                        alt="Offer Banner"
                        className="w-full h-32 object-cover rounded"
                        onError={(e) => {
                          e.currentTarget.style.display = 'none';
                        }}
                      />
                    </div>
                  </div>
                )}

                {/* Actions */}
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Actions</h3>
                  <div className="flex space-x-3">
                    <button
                      onClick={() => handleDeleteOffer(selectedOffer?.offer_id)}
                      className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 transition-colors"
                    >
                      Delete Offer
                    </button>
                    <button
                      onClick={() => setOfferDetailsModalOpen(false)}
                      className="px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700 transition-colors"
                    >
                      Close
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Edit Service Details Modal */}
      {editServiceModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between p-6 border-b border-gray-200 bg-gradient-to-r from-blue-50 to-indigo-50">
              <div className="flex items-center space-x-3">
                <div className="p-2 bg-blue-100 rounded-lg">
                  <FiEdit className="w-6 h-6 text-blue-600" />
                </div>
                <div>
                  <h2 className="text-2xl font-bold text-gray-900">
                    Edit Service Details
                  </h2>
                  <p className="text-sm text-gray-600 mt-1">
                    Update service information and description
                  </p>
                </div>
              </div>
              <button
                onClick={() => setEditServiceModalOpen(false)}
                className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                title="Close"
              >
                <FiX className="w-5 h-5" />
              </button>
            </div>

            <div className="p-6">
              <div className="space-y-6">
                {/* Service Name */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Service Name *
                  </label>
                  <input
                    type="text"
                    value={editServiceForm.service_name}
                    onChange={(e) => setEditServiceForm({...editServiceForm, service_name: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                    placeholder="Enter service name"
                  />
                </div>

                {/* Service Description */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Description
                  </label>
                  <textarea
                    value={editServiceForm.description}
                    onChange={(e) => setEditServiceForm({...editServiceForm, description: e.target.value})}
                    rows={4}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors resize-none"
                    placeholder="Enter service description"
                  />
                </div>

                {/* Service Locations */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Locations
                  </label>

                  {/* Location Tags Display */}
                  <div className="flex flex-wrap gap-2 mb-3">
                    {locationTags.map((location, index) => (
                      <div
                        key={index}
                        className="flex items-center bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-sm font-medium"
                      >
                        <span>{location}</span>
                        <button
                          onClick={() => removeLocationTag(index)}
                          className="ml-2 text-blue-600 hover:text-blue-800 transition-colors"
                          title="Remove location"
                        >
                          <FiX className="w-3 h-3" />
                        </button>
                      </div>
                    ))}
                  </div>

                  {/* Location Input */}
                  <div className="relative">
                    <input
                      type="text"
                      value={locationInput}
                      onChange={(e) => setLocationInput(e.target.value)}
                      onKeyPress={handleLocationKeyPress}
                      onBlur={addLocationTag}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                      placeholder="Type location and press Enter or comma to add"
                    />
                    {locationInput.trim() && (
                      <button
                        onClick={addLocationTag}
                        className="absolute right-2 top-1/2 transform -translate-y-1/2 bg-blue-600 text-white p-1 rounded-md hover:bg-blue-700 transition-colors"
                        title="Add location"
                      >
                        <FiPlus className="w-4 h-4" />
                      </button>
                    )}
                  </div>

                  <p className="text-sm text-gray-500 mt-1">
                    Type a location and press Enter, comma, or click the + button to add it as a tag
                  </p>
                </div>

                {/* Action Buttons */}
                <div className="flex justify-end space-x-3 pt-4 border-t">
                  <button
                    onClick={() => setEditServiceModalOpen(false)}
                    className="px-6 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={saveServiceDetails}
                    disabled={editServiceLoading}
                    className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                  >
                    {editServiceLoading ? (
                      <>
                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                        Saving...
                      </>
                    ) : (
                      <>
                        <FiSave className="w-4 h-4 mr-2" />
                        Save Changes
                      </>
                    )}
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
